  ('optician-moex-00209', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列那一條神經不經由眶上裂進入眼球？', '["三叉神經", "動眼神經", "外展神經", "顏面神經"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00210', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關鞏膜之敘述，下列何者正確？', '["高齡者因鞏膜過度增生而產生眼角膜輪部周圍白色老人環（cornealarcussenilis）", "幼童因鞏膜較厚而呈藍白色", "自體免疫疾病和鞏膜炎有關", "瞼結膜（palpebralconjunctiva）緊密附著於鞏膜表面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00211', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列何者為鞏膜與角膜相異之處？①主要結構成分  ②纖維排列方式  ③纖維直徑  ④含水量', '["僅", "", "", "僅"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00212', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '50歲的會計師，年輕時視力測量都可達1.0，自覺眼睛狀況很好；五年前開始覺得看近物有模糊的現象， 而且看久了會頭痛，雖然一直都沒有去配眼鏡矯正，但最近突然覺得看書看電腦變比較輕鬆清楚了。有關 這些現象的解釋說明，下列何者正確？', '["看近物的時候，睫狀肌要用力，此時懸韌帶拉緊，水晶體屈光度會增加", "隨著年紀老化，水晶體的囊變厚，密度增加，彈性變差，看近處會變吃力，也就是俗稱的老花眼", "若有後囊性白內障形成，近視度數增加，有些人會發現反而看近處變清楚了", "當他60歲的時候，水晶體的體積會比他在25歲的時候小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00213', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關房水的敘述，下列何者錯誤？', '["房水由小橫樑網（trabecularmeshwork）離開前房", "房水排出受阻會導致眼壓升高", "房水由角膜所產生", "房水協助維持眼球固定外形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00214', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '關於視網膜血流供應，下列敘述何者正確？', '["視網膜內層2/3組織由視網膜血流供應，外層1/3則由脈絡膜血流供給", "脈絡膜血流供應主要源自前睫狀動脈（anteriorciliaryartery）", "視網膜血流供應主要源自睫後長動脈（longposteriorciliaryartery）", "血液供應主要源自於外頸動脈（externalcarotidartery）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00215', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關視神經之敘述，下列何者錯誤？', '["可分為眼球內、眼窩內、管內和顱內四個部分", "眼球內部分的血液供應來自於短睫狀後動脈（shortposteriorciliaryarteries）", "由1,200,000髓鞘軸突（myelinatedaxons）組成，約90%是大直徑（2到10微米）", "眼球內部分的視盤（opticdisc）直徑約1.5毫米，位於黃斑部的內側約3毫米處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00216', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關視覺路徑，下列敘述何者錯誤？', '["光線由視網膜接收，往後經由視束（optictract）直接連接到達外側膝狀體（lateralgeniculatebody）", "光線由視網膜接收，往後經由視放射（opticradiation）直接連接到達視覺皮質（visualcortex）", "光線由視網膜接收，往後經由視交叉（opticchiasm）直接連接到達視放射", "光線由視網膜接收，往後經由視神經直接連接到達視交叉（opticchiasm）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00217', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '上斜肌的作用不含下列那一項？', '["內旋（intorsion）", "下轉（depression）", "內收（adduction）", "外展（abduction）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00218', 'optician', 'optician-moex-113-5e38135e', 'sub-optician-01', NULL, 'single_choice', '睫狀神經節（ciliaryganglion）之敘述，下列何者正確？', '["睫狀神經節中有副交感神經纖維突觸（synapse）傳導", "交感神經纖維來自頸上神經節的節後，也在此突觸（synapse）傳導", "來自三叉神經節細胞體的感覺纖維傳遞來自眼睛、眼眶和面部的感覺訊息，也在此突觸（synapse）傳導", "顏面神經，也在此突觸（synapse）傳導"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "86a7e84b69d9", "answer_pdf_sha1": "9333d7143989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0906", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
